// This node checks if the WhatsApp message contains a media file or just text
const body = $('Trigger | WhatsApp Incoming Message Webhook').first().json.body;

// Check for media using NumMedia from Twilio
const hasMedia = parseInt(body.NumMedia || 0) > 0;

// Get filename from Body (Twilio sends filename in Body for documents)
const fileName = hasMedia ? body.Body : null;

return {
  intent: hasMedia ? "FILE_UPLOAD" : "TEXT_MESSAGE",
  mediaUrl: body.MediaUrl0 || null,
  mimeType: body.MediaContentType0 || null,
  fileName: fileName,
  text: hasMedia ? "" : (body.Body || "")
};

