const input = $input.first().json;

let contractText = '';

// Step 1: Check if input is a JSON string that needs parsing
if (typeof input === 'string') {
  try {
    const parsed = JSON.parse(input);
    if (parsed.Successful && parsed.TextResult) {
      contractText = parsed.TextResult;
    } else {
      contractText = input;
    }
  } catch (e) {
    // Not JSON, just use as-is
    contractText = input;
  }
}
// Step 2: Check if it's already an object with the wrapper
else if (input.Successful && input.TextResult) {
  contractText = input.TextResult;
}
// Step 3: Check for direct data fields
else if (input.data) {
  contractText = input.data;
}
else if (input.text) {
  contractText = input.text;
}
else if (input.extracted_text) {
  contractText = input.extracted_text;
}
else {
  // Last resort - stringify
  contractText = JSON.stringify(input);
}

// Step 4: Clean the text thoroughly
contractText = contractText
  // Remove the wrapper text if it somehow got through
  .replace(/\{"Successful":true,"TextResult":"/, '')
  .replace(/"\}$/, '')
  // Convert escape sequences to actual characters
  .replace(/\\r\\n/g, '\n')
  .replace(/\\n/g, '\n')
  .replace(/\\t/g, '\t')
  .replace(/\\"/g, '"')
  // Remove excessive newlines
  .replace(/\n{4,}/g, '\n\n')
  // Remove leading/trailing whitespace and newlines
  .replace(/^\s+/, '')
  .replace(/\s+$/, '')
  .trim();

// Validate that we have actual content
if (!contractText || contractText.length < 50) {
  throw new Error("Contract text is too short after cleaning. Original input: " + JSON.stringify(input).substring(0, 200));
}

// Return cleaned text
return [{
  json: {
    extracted_text: contractText,
    text_length: contractText.length,
    cleaned: true
  }
}];

