  prev.employeePhoneList ??
  prev.employeePhoneString ??
  prev.employeePhones ??
  prev.employeePhoneListString ??
  prev.employee_phone_list ??
  null;

// If still not found, try to read from top-level items (fallback)
if (!rawPhones && prev.json && typeof prev.json === 'object') {
  rawPhones = prev.json.employeePhoneList ?? prev.json.employeePhoneString ?? null;
}

// Convert whatever we have into an array of strings
let phonesArray = [];
if (!rawPhones) {
  phonesArray = [];
} else if (Array.isArray(rawPhones)) {
  phonesArray = rawPhones.map(p => (p == null ? '' : String(p)));
} else if (typeof rawPhones === 'string') {
  phonesArray = rawPhones.split(',').map(s => s.trim()).filter(Boolean);
} else {
  // Something else (number etc.)
  phonesArray = [String(rawPhones)];
}

// Normalize phones: remove non-digits, then prefix +; keep only non-empty results
phonesArray = phonesArray
  .map(p => p.trim())
  .map(p => {
    // Remove common prefixes like 'whatsapp:' or 'tel:' then non-digits
    p = p.replace(/^whatsapp:|^tel:/i, '').trim();
    // Keep only digits
    const digits = p.replace(/\D/g, '');
    if (!digits) return null;
    // If number already has country code (length > 10) just prefix +
    if (digits.length > 10) return `+${digits}`;
    // If 10 digits assume +1 by default (change if you want other default)
    if (digits.length === 10) return `+1${digits}`;
    // otherwise prefix + and keep digits
    return `+${digits}`;
  })
  .filter(Boolean);

