  match = allTasks.find(t =>
    t.task_title && t.task_title.toLowerCase().includes(identifier)
  );
  if (match) {
    console.log(`✓ Found by partial task title: Task #${match.id} - ${match.task_title}`);
    return match;
  }

  // Strategy 5: Keywords matching (all words must be present)
