let updateType = null;
let newDeadline = null;
let durationText = "";
let reason = "";
let outputContent = null;
let outputType = null;
let fileName = null;

// --- REGEX PATTERNS ---
const getTasksPattern = /(my|show|check|list|what|give|send)\s*(are|is|me)?\s*(my)?\s*(tasks?|todos?|work|status|taks?|task|tsk)/i;
const detailsPattern = /(details?|info|brief|show|detials?|deatils?)\s*(\d+)/i;

// DONE pattern - detects completion + extracts task keywords
const donePattern = /(done|finish|finsh|complete|close|completed|finished|submitted|ready|task\s+[\w\s]+\s+completed?)(\s+(\d+))?/i;

const delayPattern = /(delay|push|extend|defer|move|later)\s+(\d+)\s+(?:by\s+)?(.+)/i;

// URL pattern for attachments/links
const urlPattern = /(https?:\/\/[^\s]+)/gi;

// File attachment check
const hasFile = webhookData.body && webhookData.body.MediaUrl0;

// --- MAIN LOGIC ---
if (getTasksPattern.test(cleanMessage)) {
  intent = "get_tasks";
} 
else if (match = cleanMessage.match(delayPattern)) {
  intent = "delay_task";
  taskNumber = parseInt(match[2]);

  const delayText = match[3].trim();
  const durationMatch = delayText.match(/(\d+\s*(?:hrs?|hours?|days?|d|minutes?|mins?|m))/i);

  if (durationMatch) {
    durationText = durationMatch[1].replace(/\s+/g, '');
    reason = delayText.replace(durationMatch[0], '').trim();
    reason = reason.replace(/^(because|due to|as|since|for|coz|bcoz|bcz)/i, '').trim();
  } else {
    durationText = "1d";
    reason = delayText;
  }

  const now = new Date();
  let addTime = 0;
  const numberOnly = parseInt(durationText.replace(/[^0-9]/g, '')) || 1;

  if (durationText.match(/d/i)) {
     addTime = numberOnly * 24 * 60 * 60 * 1000;
  } else if (durationText.match(/h/i)) {
     addTime = numberOnly * 60 * 60 * 1000;
  } else if (durationText.match(/m/i)) {
     addTime = numberOnly * 60 * 1000;
  }

  newDeadline = new Date(now.getTime() + addTime).toISOString();
}
else if (match = cleanMessage.match(detailsPattern)) {
  intent = "get_details";
  taskNumber = parseInt(match[2]); 
} 
else if (donePattern.test(cleanMessage)) {
  intent = "task_complete";
  updateType = "done";

  // Extract meaningful task keywords for better matching
  let taskText = cleanMessage
    .replace(/(done|finish|finsh|complete|close|completed|finished|submitted|ready|task)/gi, '')
    .replace(urlPattern, '') 
    .trim();

  const keywords = taskText
    .split(/\s+/)
    .filter(word => word.length >= 3)
    .slice(0, 3);

  if (keywords.length > 0) {
    taskKeywords = keywords.join(' ');
  }

  // --- Handle Output (File or Link) ---
  if (hasFile) {
    outputType = 'file';
    outputContent = webhookData.body.MediaUrl0;
    fileName = webhookData.body.MediaContentType0 || 'attachment';
  } else {
    const urlMatches = originalMessage.match(urlPattern);
    if (urlMatches && urlMatches.length > 0) {
      outputContent = urlMatches[0];
      outputType = "link";
    }
  }
}

// --- OUTPUT ---
return {
  json: {
    intent: intent,
    task_number: taskNumber,
    task_keywords: taskKeywords,
    update_type: updateType,
    new_deadline: newDeadline,
    duration_text: durationText,
    reason: reason || "No reason provided",
    employee_phone: webhookData.query?.phone || webhookData.body?.From || webhookData.body?.from,
    body: message,
    output_content: outputContent,
    output_type: outputType,
    file_name: fileName
  }
};

