  daysUntilDeadline = diffMs / (1000 * 60 * 60 * 24);

  // If deadline is within 3 days (past or future)
  if (daysUntilDeadline <= 3 && daysUntilDeadline >= -1) {
    confidenceScore += 30;
  }
}

// --- Output was provided ---
