function getCleanFileName(fileName) {
  // Remove timestamp prefix like "1776952320011-" 
  const nameNoExt = fileName.replace(/\.[^.]+$/, '');
  const withoutTimestamp = nameNoExt.replace(/^\d{10,}-/, '');
  return normalize(withoutTimestamp);
}

// Expand a phrase/word using synonym map
function expandPhrase(phrase) {
  const normalized = normalize(phrase);
  const found = new Set([normalized]);

  // Direct hit in SYNONYM_MAP
  if (SYNONYM_MAP[normalized]) {
    SYNONYM_MAP[normalized].forEach(s => found.add(normalize(s)));
  }

  // Also check if phrase CONTAINS a key
  for (const [key, vals] of Object.entries(SYNONYM_MAP)) {
    if (normalized.includes(key) || key.includes(normalized)) {
      vals.forEach(s => found.add(normalize(s)));
      found.add(normalize(key));
    }
  }

  return [...found];
}

// Build full word list from intent signals
function buildSearchTerms() {
  const terms = new Set();

  // From file_keywords - HIGHEST PRIORITY
  for (const kw of fileKeywords) {
    const expanded = expandPhrase(kw);
    expanded.forEach(t => terms.add(t));

    // Also add individual words from multi-word keywords
    kw.split(' ').forEach(word => {
      if (word.length > 2) {
        terms.add(normalize(word));
        expandPhrase(normalize(word)).forEach(t => terms.add(t));
      }
    });
  }

  // From task_text - HIGH PRIORITY
  const taskWords = taskText.split(' ').filter(w => w.length > 2);
  for (const word of taskWords) {
    terms.add(normalize(word));
    expandPhrase(normalize(word)).forEach(t => terms.add(t));
  }

  // Full task text phrase expansion
  expandPhrase(taskText).forEach(t => terms.add(t));

  // Combined keyword + task phrase
  if (fileKeywords.length > 0) {
    const combined = fileKeywords.join(' ') + ' ' + taskText;
    expandPhrase(combined).forEach(t => terms.add(t));
  }

  // Remove very short/generic
  const IGNORE = new Set(['a', 'an', 'the', 'for', 'to', 'of', 'in', 'on',
                          'by', 'and', 'or', 'is', 'it', 'do', 'me', 'my',
                          'file', 'doc', 'document', 'task', 'work', 'give',
                          'send', 'share', 'assign', 'need', 'please', 'high',
                          'fidelity', 'create', 'make', 'get', 'set', 'put',
                          'john', 'with', 'from', 'this', 'that', 'has',
                          'have', 'had', 'was', 'were', 'are', 'be', 'been']);

  return [...terms].filter(t => t && t.length > 2 && !IGNORE.has(t));
}

// ─────────────────────────────────────────
// 4. SCORE EACH FILE
// ─────────────────────────────────────────
function scoreFile(file, searchTerms) {
  const rawFileName  = String(file.file_name    || '');
  const rawFilePath  = String(file.file_path    || '');
  const rawProjectNm = String(file.project_name || '');

  const cleanName    = getCleanFileName(rawFileName);
  const normPath     = normalize(rawFilePath);
  const normProject  = normalize(rawProjectNm);
  const fileExt      = (rawFileName.match(/\.([^.]+)$/) || [])[1] || '';

  let score = 0;
  const reasons = [];

  for (const term of searchTerms) {
    if (!term || term.length < 3) continue;

    // ── A. EXACT match in clean file name (strongest signal)
    if (cleanName === term) {
      score += 100;
      reasons.push(`EXACT_NAME_MATCH: "${term}"`);
    }

    // ── B. File name CONTAINS the term
    else if (cleanName.includes(term)) {
      score += 60;
      reasons.push(`NAME_CONTAINS: "${term}"`);
    }

    // ── C. Term CONTAINS the file name (file name is a substring of term)
    else if (term.includes(cleanName) && cleanName.length >= 4) {
      score += 40;
      reasons.push(`TERM_CONTAINS_NAME: "${term}"`);
    }

    // ── D. File name words match term
    else {
      const nameWords = cleanName.split(' ');
      for (const nw of nameWords) {
        if (nw.length < 3) continue;
        if (nw === term) {
          score += 50;
          reasons.push(`NAME_WORD_EXACT: "${nw}" = "${term}"`);
        } else if (nw.includes(term) || term.includes(nw)) {
          score += 25;
          reasons.push(`NAME_WORD_PARTIAL: "${nw}" ~ "${term}"`);
        }
      }
    }

    // ── E. Path contains term (weaker, path has noise)
    if (normPath.includes(term)) {
      score += 8;
      reasons.push(`PATH_CONTAINS: "${term}"`);
    }
  }

  // ── F. Extension bonus (right file type for the task)
  const designExts    = ['fig', 'sketch', 'xd', 'ai', 'psd', 'pdf', 'png', 'jpg', 'svg'];
  const docExts       = ['pdf', 'doc', 'docx', 'txt', 'md', 'notion'];
  const codeExts      = ['json', 'env', 'txt', 'yaml', 'yml', 'js', 'ts'];

  const isDesignTask  = searchTerms.some(t =>
    ['design', 'ui', 'ux', 'figma', 'wireframe', 'mockup', 'element', 'visual'].includes(t));
  const isApiTask     = searchTerms.some(t =>
    ['api', 'apikey', 'token', 'credential', 'key', 'secret'].includes(t));
  const isBrandTask   = searchTerms.some(t =>
    ['brand', 'branding', 'brandkit', 'logo', 'identity', 'styleguide'].includes(t));

  if (isDesignTask  && designExts.includes(fileExt))  { score += 15; reasons.push(`EXT_DESIGN: .${fileExt}`); }
  if (isApiTask     && codeExts.includes(fileExt))    { score += 15; reasons.push(`EXT_API: .${fileExt}`); }
  if (isBrandTask   && [...designExts, ...docExts].includes(fileExt)) {
    score += 15;
    reasons.push(`EXT_BRAND: .${fileExt}`);
  }

  // ── G. Project name match bonus (files from same project get small boost)
  if (projectName && normProject.includes(projectName)) {
    score += 10;
    reasons.push(`PROJECT_MATCH`);
  }

  // ── H. Penalize if ZERO meaningful overlap with any search term
  if (score === 0) {
    score = -999;
    reasons.push('NO_MATCH');
  }

  return {
    file,
    clean_file_name:  cleanName,
    file_extension:   fileExt,
    match_score:      score,
    match_reasons:    [...new Set(reasons)],
    search_terms_used: searchTerms,
  };
}

// ─────────────────────────────────────────
// 5. RUN MATCHING
// ─────────────────────────────────────────
const searchTerms = buildSearchTerms();

if (searchTerms.length === 0) {
  return [{
    json: {
