const best   = scored[0];
const second = scored[1];

// Confidence
let confidence = 'low';
if (best.match_score >= 80)  confidence = 'very_high';
else if (best.match_score >= 50) confidence = 'high';
else if (best.match_score >= 25) confidence = 'medium';

// Ambiguity check
const ambiguous = second && Math.abs(best.match_score - second.match_score) <= 10;

// ─────────────────────────────────────────
// 6. RETURN SINGLE BEST MATCH ONLY
// ─────────────────────────────────────────
return [{
  json: {
